INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-57f41407-moex-00082', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '「在超商排隊是我最有感的事情，我其實不太能忍受花上三分鐘等待餐點、咖啡或結帳，就算是我願 意等，心裡也是百般折磨。一來是，當我使用像超商這樣的商店時，我預期它就是會非常迅速地結帳 並且拿到我想買的東西；但是另一方面，有時候我更覺得是想取得自己對時間的掌控權。」 根據上文，下列選項最符合文意的是：', '["超商的結帳程序，總是能夠符合作者的想法", "超商提供便利快捷的服務，讓作者備受禮遇", "超商多樣化商品，讓作者易取得想買的東西", "藉超商的快速服務，作者預期可以爭取時間"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00083', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '「文學宜講究天真自然，若能把生活中靜觀或微悟化為文字，必然能感動在日常裡辛勞奔波的讀者。 不過人生何其平凡，要將人人都懂的酸甜苦澀，提升為可供品味的文學，作家除了文藝技巧的嫻熟， 最主要必須有過人的處世意境，才能在常人忽略的事物中，得到發人深省的延伸思考。」 根據上文，作家最須具備的特質是：', '["天真自然的本性", "嫻熟的文藝技巧", "酸甜苦澀的人生", "處世的靜觀微悟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00084', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '「我看到一些堅苦卓絕的人，在壯年時已失去奮鬥的目標，如早凋的花朵，令人感慨；我也看到一些 較晚開竅的人被當作遲鈍，連公平的學習機會都沒有，被淘汰在滾滾人潮之外，令人惋惜。但是，我 更看到，幸虧這個世界有些慢開竅的人，他們慢條斯理的踏著上帝給他的步伐，不至迷失在偏差的洪 流中，令人羨慕。」 根據上文，下列選項最合乎文意的是：', '["咖啡把歲月喝掉，舌尖的快樂是甜還是苦呢", "大象走得慢，但是一步一步，還是會到終點", "駱駝穿過針的眼，比財主進神的國還容易呢", "即使最肥沃的土壤，若不耕耘也會雜草叢生"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00085', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '「法國作家安德烈．紀德如是說：『對我而言，閱讀一個人的作品並不僅是理解文句的意義，而是與 他一同啟程，並肩遊歷。』而在這樣的旅程過後，歸來的旅人和去前早已不同。」 根據上文，下列選項最適當的是：', '["在閱讀之前，讀者應先瞭解作者背景資料", "現實體驗更珍貴，讀萬卷書不如行萬里路", "真正的閱讀可理解作品，使自我產生變化", "閱讀與旅行，均有助於人們跳脫文字框架"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00086', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '「在古老的童話裡，魔法、隱身術、荒謬的遭遇、極端而又快速的改變等等，常常讓我們害怕和不安； 但是如果沒有這些令人戰慄的事件撞擊，孩童的心靈就不可能得到釋放，更不可能進入童話書裡那個 美麗又奇妙的世界裡去了。孩童的時候依賴童話，成人之後就要依賴藝術，依賴一種突然的狂喜來釋 放我們的心靈。」 下列選項，何者最符合文意？', '["童話和藝術的創作原理相異，因此產生不同的面貌", "童話與藝術能使人感到愉悅，具有釋放心靈的功能", "孩童透過不安，學習抵抗權勢，使身心靈獲得自由", "藝術的功能是透過審美機制刺激我們學習新的事物"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00087', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '「我也嘗試在夏日黃昏走進空空的市場，依靠嗅覺找到白天母親挑選菜蔬的攤子，九層塔的氣味、薑 蒜的氣味、芫荽的氣味，或者豌豆苗有點委屈的清香，像漸行漸遠不太騷擾人間的平靜氣味。母親教 會我用嗅覺認識整個市場眾生的歡悅、眾生的哀傷。彷彿她仍然帶領著我，走在世界各處，走在人群 中，在嗅覺裡知道愛或者恨，擁抱的溫暖、廝殺的血腥，生的氣味，死亡的氣味。」 根據上文，下列選項最符合文意的是：', '["市場中寂寥平靜的氛圍帶給我和母親豐富多元的嗅覺體驗", "我遺傳母親敏銳的嗅覺在市場的各種菜肉氣息中品味佳餚", "母親教我運用與生俱來的感官能力分辨眾生的生死與情緒", "我隨著母親在市場的生活氣息中體會芸芸眾生的現實人生"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00088', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '「朱光潛先生有一句話讓我非常認同，他說：『美感的世界是一個純粹意象的世界，欣賞藝術是從實 用的世界走向理想的世界，也就是沒有利害關係的世界。』沒有錯，當每一件事情都有利害的時候， 你怎能有平靜的心靈去欣賞它？因此，我們每一個人的內在都應該有一些事情，是超越利害關係的、 是不求回報的，這樣我們才能從另外一個領域發現自己，找到讓自己安靜的境域。」 根據上文，下列選項何者最符合文意？', '["超越利害關係、不求回報，是我們發現自己的保證", "每一個人的內在都有走向藝術、走向美感世界的渴望", "只有藝術才能讓人跳脫利害關係，發現讓自己平靜的境域", "欣賞藝術就是走向純粹意象的理想世界、沒有利害關係的世界"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00089', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '「在長大的過程，一步一步，隨著年齡的增長，隨著生命經驗的擴大，我們的味覺也在經驗不同的記 憶，我在甜味裡，記憶幸福滿足，在酸味裡，學習失落的悵惘，在辣味裡，體會熱烈放肆逾越規矩的 快感。」 根據上文，下列選項何者不符合文意？', '["體會人生的美好如蜜糖", "失落悵惘如同檸檬滋味", "感受人生之生老病死滋味", "強烈感官刺激滋味如辣椒"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00090', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '「當我們閱讀報章雜誌的時候，若要保持獨立的判斷能力，首先就須清楚地在腦海中先分離出中性語 言及價值語言，過濾誇張及臆測性的語言，發現較為中性的事實。『中性語言』就是指不包含主觀價 值判斷、嘗試表達中性事實的語言。『價值語言』即是包含主觀價值判斷及各種臆測性的語言。」 根據上文，下列那一選項屬於「中性語言」？', '["他生來就是勞碌命", "我今天看了一本書", "這是令人振奮的消息", "別作忘恩負義的小人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00091', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '「新生水處理系統除了解決工業、商業和民生用水問題，也大幅降低海洋汙染，因為只有少部分無法 淨化的汙水會排入大海之中。聯合國數據指出，全球高達80%的國家將未經處理的汙水，或無法再次 使用的廢水排放進入生態系統之中，造成海洋環境汙染。」 根據上文，下列選項敘述何者正確？', '["新生水處理系統無法完全淨化汙水", "新生水處理系統不可用於民生用水", "經濟發達有助於解決汙水排放問題", "大多數國家已經有效處理汙水排放"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL)
